#include <vector>
#include <unordered_set>
using namespace std;

int largestPositiveK(vector<int> nums) {
    unordered_set<int> s(nums.begin(), nums.end());
    int max_k = -1;
    for (int num : nums) {
        if (num > 0) {
            if (s.count(-num)) {
                if (num > max_k) {
                    max_k = num;
                }
            }
        } else {
            int pos = -num;
            if (s.count(pos)) {
                if (pos > max_k) {
                    max_k = pos;
                }
            }
        }
    }
    return max_k;
}
